local getFilteredLabels = Core.getFilteredLabels

local Window = Library:CreateWindow({
	Title            = "COMBOWICK",
	Footer           = "Create",
	ShowCustomCursor = false,
	Size             = UDim2.new(0, 320, 0, 460),
})

local Tabs = {
	Create          = Window:AddTab("Create",      "zap"),
	Auto            = Window:AddTab("Auto",        "repeat"),
	["การตั้งค่า UI"] = Window:AddTab("การตั้งค่า UI", "settings"),
}

local SelectGroup = Tabs.Create:AddLeftGroupbox("การเลือกสัตว์เลี้ยง")

SelectGroup:AddDropdown("RarityFilter", {
	Text     = "กรองตามความหายาก",
	Values   = RARITY_FILTERS,
	Default  = "All",
	Callback = function(v)
		state.filterRarity     = v
		state.selectedPetLabel = nil
		Options.PetSelect:SetValues(getFilteredLabels())
	end,
})

SelectGroup:AddDivider()

SelectGroup:AddDropdown("PetSelect", {
	Text     = "เลือกสัตว์เลี้ยง",
	Values   = getFilteredLabels(),
	Default  = nil,
	Callback = function(v)
		state.selectedPetLabel = v
	end,
})

local OptionsGroup = Tabs.Create:AddRightGroupbox("การตั้งค่าการสร้าง")

OptionsGroup:AddDropdown("MutationSelect", {
	Text     = "Mutation",
	Values   = MUTATIONS,
	Default  = "Normal",
	Callback = function(v)
		state.selectedMutation = v
	end,
})

OptionsGroup:AddDivider()

OptionsGroup:AddDropdown("RarityOverride", {
	Text     = "เปลี่ยนความหายาก",
	Values   = RARITY_OVERRIDES,
	Default  = "Default",
	Callback = function(v)
		state.selectedRarity = v
	end,
})

OptionsGroup:AddDivider()

local StatusLabel = OptionsGroup:AddLabel("สถานะ: ไม่ทำงาน", true)

OptionsGroup:AddToggle("AutoSpawn", {
	Text     = "สร้างอัตโนมัติ",
	Default  = false,
	Callback = function(v)
		if v and not state.selectedPetLabel then
			StatusLabel:SetText("สถานะ: ยังไม่ได้เลือกสัตว์เลี้ยง")
			Options.AutoSpawn:SetValue(false)
			return
		end
		state.autoSpawn = v
		StatusLabel:SetText(v and "Status: Creating..." or "สถานะ: ไม่ทำงาน")
	end,
})

OptionsGroup:AddSlider("SpawnDelay", {
	Text     = "หน่วงเวลาการสร้างสัตว์เลี้ยง (วินาที)",
	Min      = 0.1,
	Max      = 10,
	Default  = 1,
	Rounding = 1,
	Callback = function(v)
		state.spawnDelay = v
	end,
})

local AutoGroup = Tabs.Auto:AddLeftGroupbox("Automation")

AutoGroup:AddToggle("AutoRebirth", {
	Text     = "เกิดใหม่อัตโนมัติ",
	Default  = false,
	Callback = function(v)
		state.autoRebirth = v
	end,
})

AutoGroup:AddDivider()

AutoGroup:AddToggle("AutoSpeedUpgrade", {
	Text     = "อัปเกรดความเร็วอัตโนมัติ",
	Default  = false,
	Callback = function(v)
		state.autoSpeedUpgrade = v
	end,
})

AutoGroup:AddDivider()

AutoGroup:AddToggle("AutoSellAll", {
	Text     = "ขายไอเทมในคลังอัตโนมัติ",
	Default  = false,
	Callback = function(v)
		state.autoSellAll = v
	end,
})

local MenuGroup = Tabs["การตั้งค่า UI"]:AddLeftGroupbox("Menu")
MenuGroup:AddLabel("ปุ่มลัดเปิด/ปิดเมนู")
	:AddKeyPicker("MenuKeybind", { Default = "RightShift", NoUI = true, Text = "ปุ่มลัดเปิด/ปิดเมนู" })
MenuGroup:AddButton("ออกจากสคริปต์", function() Library:Unload() end)

Library.ToggleKeybind = Options.MenuKeybind
ThemeManager:SetLibrary(Library)
SaveManager:SetLibrary(Library)
SaveManager:IgnoreThemeSettings()
